import React, { useState, useRef, useEffect } from 'react';

function DrawingCanvas({ cameraData, onSave, onBack }) {
  const [drawing, setDrawing] = useState(false);
  const [lines, setLines] = useState([]);
  const [ix, setIx] = useState(-1);
  const [iy, setIy] = useState(-1);
  const canvasRef = useRef(null);
  const imageRef = useRef(null);

  const handleMouseDown = (e) => {
    if (!canvasRef.current || !imageRef.current || lines.length >= 2) return;

    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    setDrawing(true);
    setIx(x);
    setIy(y);
  };

  const handleMouseMove = (e) => {
    if (!drawing || !canvasRef.current || lines.length >= 2) return;

    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    const ctx = canvas.getContext('2d');
    redrawAll();

    ctx.beginPath();
    ctx.moveTo(ix, iy);
    ctx.lineTo(x, y);

    if (lines.length === 0) {
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 2;
      ctx.stroke();
    } else if (lines.length === 1) {
      drawArrow(ctx, ix, iy, x, y, '#ff0000', 2);
    }
  };

  const handleMouseUp = (e) => {
    if (!drawing || !canvasRef.current || lines.length >= 2) return;

    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    const normStartX = ix / canvas.width;
    const normStartY = iy / canvas.height;
    const normEndX = x / canvas.width;
    const normEndY = y / canvas.height;

    const newLine = {
      start: { x: normStartX, y: normStartY },
      end: { x: normEndX, y: normEndY }
    };

    setLines([...lines, newLine]);
    setDrawing(false);

    const ctx = canvas.getContext('2d');

    if (lines.length === 0) {
      ctx.beginPath();
      ctx.moveTo(ix, iy);
      ctx.lineTo(x, y);
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 3;
      ctx.stroke();
    } else if (lines.length === 1) {
      drawArrow(ctx, ix, iy, x, y, '#ff0000', 4);
    }
  };

  const drawArrow = (ctx, fromX, fromY, toX, toY, color, width) => {
    const headLength = 20;
    const angle = Math.atan2(toY - fromY, toX - fromX);

    ctx.beginPath();
    ctx.moveTo(fromX, fromY);
    ctx.lineTo(toX, toY);
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    ctx.stroke();

    ctx.beginPath();
    ctx.moveTo(toX, toY);
    ctx.lineTo(
      toX - headLength * Math.cos(angle - Math.PI / 6),
      toY - headLength * Math.sin(angle - Math.PI / 6)
    );
    ctx.lineTo(
      toX - headLength * Math.cos(angle + Math.PI / 6),
      toY - headLength * Math.sin(angle + Math.PI / 6)
    );
    ctx.closePath();
    ctx.fillStyle = color;
    ctx.fill();
  };

  const redrawAll = () => {
    if (!canvasRef.current || !imageRef.current) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    lines.forEach((line, index) => {
      const startX = line.start.x * canvas.width;
      const startY = line.start.y * canvas.height;
      const endX = line.end.x * canvas.width;
      const endY = line.end.y * canvas.height;

      if (index === 0) {
        ctx.beginPath();
        ctx.moveTo(startX, startY);
        ctx.lineTo(endX, endY);
        ctx.strokeStyle = '#000000';
        ctx.lineWidth = 3;
        ctx.stroke();
      } else if (index === 1) {
        drawArrow(ctx, startX, startY, endX, endY, '#ff0000', 4);
      }
    });
  };

  const handleSave = () => {
    if (lines.length < 2) {
      alert('Cần vẽ đủ Axis và Coord');
      return;
    }

    const config = {
      zone: [{
        ID: generateUUID(),
        type: 1,
        axis: [lines[0].start.x, lines[0].start.y, lines[0].end.x, lines[0].end.y],
        coord: [lines[1].start.x, lines[1].start.y, lines[1].end.x, lines[1].end.y]
      }],
      reid: {
        faiss_switch: 0.6,
        faiss_staff_db: 0.8
      }
    };

    onSave(config);
  };

  const generateUUID = () => {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
      const r = Math.random() * 16 | 0;
      const v = c === 'x' ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    });
  };

  useEffect(() => {
    redrawAll();
  }, [lines]);

  return (
    <div className="drawing-canvas">
      <div className="instructions">
        <h4>Hướng dẫn vẽ:</h4>
        <p>1. Kéo thả chuột vẽ Axis (line đen)</p>
        <p>2. Kéo thả chuột vẽ Coord (mũi tên đỏ)</p>
      </div>

      <div className="canvas-container">
        <img 
          ref={imageRef}
          src={cameraData.imagePreview} 
          alt="Camera"
          onLoad={() => {
            if (canvasRef.current && imageRef.current) {
              canvasRef.current.width = imageRef.current.width;
              canvasRef.current.height = imageRef.current.height;
              redrawAll();
            }
          }}
        />
        <canvas
          ref={canvasRef}
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={() => setDrawing(false)}
        />
      </div>

      <div className="status">
        <p>Axis: {lines.length >= 1 ? '✓' : '⏳'}</p>
        <p>Coord: {lines.length >= 2 ? '✓' : '⏳'}</p>
      </div>

      <div className="actions">
        <button onClick={onBack} className="btn-back">← Quay lại</button>
        <button onClick={handleSave} className="btn-save">Lưu camera</button>
      </div>

      <style jsx>{`
        .drawing-canvas {
          padding: 20px;
        }

        .instructions {
          background: #f8f9fa;
          padding: 15px;
          border-radius: 4px;
          margin-bottom: 20px;
        }

        .instructions h4 {
          margin: 0 0 10px 0;
        }

        .instructions p {
          margin: 5px 0;
          color: #666;
        }

        .canvas-container {
          position: relative;
          border: 2px solid #ddd;
          border-radius: 4px;
          overflow: hidden;
          margin: 20px 0;
        }

        .canvas-container img {
          display: block;
          width: 100%;
          height: auto;
        }

        .canvas-container canvas {
          position: absolute;
          top: 0;
          left: 0;
          width: 100%;
          height: 100%;
          cursor: crosshair;
        }

        .status {
          display: flex;
          gap: 20px;
          padding: 15px;
          background: #e9ecef;
          border-radius: 4px;
          margin: 15px 0;
        }

        .status p {
          margin: 0;
          font-weight: 500;
        }

        .actions {
          display: flex;
          gap: 10px;
          margin-top: 20px;
        }

        .btn-back,
        .btn-save {
          flex: 1;
          padding: 12px;
          border: none;
          border-radius: 4px;
          font-size: 14px;
          cursor: pointer;
        }

        .btn-back {
          background: #6c757d;
          color: white;
        }

        .btn-save {
          background: #28a745;
          color: white;
        }

        .btn-back:hover {
          background: #5a6268;
        }

        .btn-save:hover {
          background: #218838;
        }
      `}</style>
    </div>
  );
}

export default DrawingCanvas;
